+		dayEnd := dayStart.Add(24 * time.Hour)
+		filter.UpdatedAfter = &dayStart
+		filter.UpdatedBefore = &dayEnd
+	case OpGreater:
+		filter.UpdatedAfter = &t
+	case OpGreaterEq:
+		filter.UpdatedAfter = &t
+	case OpLess:
